// Chart.js 与插件必须钉到同一模块 URL,否则各自持有不同 registry
import { Chart, registerables } from 'https://cdn.jsdelivr.net/npm/chart.js@4.5.1/+esm';
import { SankeyController, Flow } from 'https://cdn.jsdelivr.net/npm/chartjs-chart-sankey@0.15.0/+esm';
Chart.register(...registerables, SankeyController, Flow);
const host = document.getElementById('chart'); host.style.height = '400px'; const canvas = document.createElement('canvas'); host.appendChild(canvas);
new Chart(canvas, { ...data.config, options: { responsive: true, maintainAspectRatio: false, ...(data.config.options ?? {}) } });

